b-1e5c-4d91-aef8-9ae871323302","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Desconsiderei a Gupy do ICP (apesar do tamanho de empresa estar casando com o que enxergávamos  como ICP,  na prática não foi)\nTivemos G7 e ENIAC desde então, mantendo 3/6","parentId":"19e3cf82-45f4-4243-8879-65946c70da4a","previousState":null},{"id":"19e3cf82-45f4-4243-8879-65946c70da4a","createdAt":"2023-02-13T15:22:46.697Z","value":50,"confidence":100,"keyResultId":"d6dbbc4b-1e5c-4d91-aef8-9ae871323302","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Nenhum fechamento nos últimos 7 dias","parentId":"3e397378-9463-43f4-a48e-f36b15f49fa4","previousState":null},{"id":"3e397378-9463-43f4-a48e-f36b15f49fa4","createdAt":"2023-02-02T18:48:39.542Z","value":50,"confidence":100,"keyResultId":"d6dbbc4b-1e5c-4d91-aef8-9ae871323302","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Irei deixar na checklist os novos clientes e assinalar aqueles  que são ICP (Mid Market)","parentId":null,"previousState":null}],"objective":{"id":"4f352889-3a4b-4e4b-8fdd-de6371e86e1c","createdAt":"2023-01-13T14:19:59.669Z","title":"Create long-term relevance in our customers","description":null,"updatedAt":"2023-01-13T16:24:12.750Z","cycleId":"4f01f61e-1616-40fa-8363-a930a2db2351","ownerId":"5aec0149-5535-42fb-b3d3-c20a5bda80c8","teamId":"f6790108-2b16-4077-bed0-103fc38175dd","mode":"PUBLISHED","cycle":{"id":"4f01f61e-1616-40fa-8363-a930a2db2351","createdAt":"2023-01-12T18:32:30.038Z","period":"2023","cadence":"YEARLY","active":true,"dateStart":"2023-01-01T00:00:00.000Z","dateEnd":"2023-12-31T00:00:00.000Z","updatedAt":"2023-01-12T18:32:30.038Z","teamId":"f6790108-2b16-4077-bed0-103fc38175dd","parentId":null}},"team":{"id":"f6790108-2b16-4077-bed0-103fc38175dd","createdAt":"2021-03-01T12:59:54.029Z","name":"Bud","updatedAt":"2021-10-12T16:39:15.305Z","ownerId":"16e46da6-39fc-4034-84c9-7b59a825d6e4","description":"Bud é a plataforma que te ajuda a implementar OKR de um jeito leve, envolvente e colaborativo.","gender":"MALE","parentId":null}},{"id":"88c84700-4026-40e6-a539-a43660bbb518","createdAt":"2023-01-13T14:16:59.242Z","title":"MRR Growth MoM 10%","initialValue":"0","goal":"10","format":"PERCENTAGE","type":"ASCENDING","updatedAt":"2023-01-16T11:20:19.551Z","ownerId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","objectiveId":"6d77bd7f-a5d8-42b3-879d-51e11c8fc00d","teamId":"f6790108-2b16-4077-bed0-103fc38175dd","description":"","mode":"PUBLISHED","lastUpdatedBy":null,"commentCount":{"issue":0,"comment":0,"praisal":0,"question":0,"alignment":0,"suggestion":0,"improvement":0},"checkIns":[{"id":"2970b9ba-c4d8-4d79-940c-ecbc0ab3b131","createdAt":"2023-07-03T20:10:07.084Z","value":2.06,"confidence":32,"keyResultId":"88c84700-4026-40e6-a539-a43660bbb518","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"We don't have an official number for June","parentId":"1dcbd9d0-7779-412e-8871-3f5e23efc340","previousState":{"goal":"10","mode":"PUBLISHED","type":"ASCENDING","title":"MRR Growth MoM 10%","format":"PERCENTAGE","ownerId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","description":""}},{"id":"1dcbd9d0-7779-412e-8871-3f5e23efc340","createdAt":"2023-06-18T21:27:49.615Z","value":2.06,"confidence":32,"keyResultId":"88c84700-4026-40e6-a539-a43660bbb518","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Monthly indicator","parentId":"1478d2d2-cc08-49ce-97e0-654f54097ef4","previousState":null},{"id":"1478d2d2-cc08-49ce-97e0-654f54097ef4","createdAt":"2023-06-02T14:17:01.745Z","value":2.06,"confidence":32,"keyResultId":"88c84700-4026-40e6-a539-a43660bbb518","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"We don't have an official number (based on our P&L sheet), but it is estimated to be around -6% in May, which will adjust this indicator to 0.8%.\nMy thoughts for May: We invested a significant amount of energy in Web Summit leads, and even though they were MQLs (Managers, Heads, and C-Level from companies with around 100-1000 employees), their time to advance in our sales funnel was not optimal. On the other hand, individuals who attended our OKR Workshops are more likely to have identified issues with new work methods and tend to perform better in our funnel.\nFor this month, we have planned an OKR workshop in Brazil, and we are hopeful for a potential talk with Amcham. Additionally, we aim to strengthen our relationship with StarSe, Semesp, HSM, and MIT Sloan.\n\nNão temos um número oficial (com base em nossa planilha de P&L), mas estima-se que seja em torno de -6% em maio, o que ajustará esse indicador para 0,8%.\nMinhas reflexões para maio: Investimos bastante energia em leads da Web Summit e, mesmo que eles tenham sido MQLs (Gerentes, Chefes e Executivos de nível C de empresas com cerca de 100-1000 funcionários), o tempo de avanço deles em nosso funil de vendas não foi o ideal. Por outro lado, as pessoas que participaram de nossos Workshops de OKR têm maior probabilidade de ter identificado questões relacionadas a novas formas de trabalho e tendem a ter um desempenho melhor em nosso funil.\nPara este mês, temos planejado um workshop de OKR no Brasil e temos esperança de realizar uma palestra com a Amcham. Além disso, buscamos fortalecer nosso relacionamento com a StarSe, Semesp, HSM e MIT Sloan.","parentId":"ddf7bd8a-7766-40d2-addb-8131be84491c","previousState":null},{"id":"ddf7bd8a-7766-40d2-addb-8131be84491c","createdAt":"2023-05-26T13:56:56.514Z","value":2.06,"confidence":66,"keyResultId":"88c84700-4026-40e6-a539-a43660bbb518","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Monthly Indicator, but probably this month will perform poorly","parentId":"d4d8ae79-8313-4aa2-b944-c07e919234fa","previousState":null},{"id":"d4d8ae79-8313-4aa2-b944-c07e919234fa","createdAt":"2023-05-19T11:41:31.793Z","value":2.06,"confidence":66,"keyResultId":"88c84700-4026-40e6-a539-a43660bbb518","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Monthly Indicator","parentId":"60fc6c2e-151a-4393-ad6b-099dfff80dc6","previousState":null},{"id":"60fc6c2e-151a-4393-ad6b-099dfff80dc6","createdAt":"2023-05-12T11:35:28.176Z","value":2.06,"confidence":66,"keyResultId":"88c84700-4026-40e6-a539-a43660bbb518","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Fechamento mensal","parentId":"99d7eb53-c5b7-43cf-b42d-48f32af7bb9d","previousState":null},{"id":"99d7eb53-c5b7-43cf-b42d-48f32af7bb9d","createdAt":"2023-05-08T12:39:24.352Z","value":2.06,"confidence":66,"keyResultId":"88c84700-4026-40e6-a539-a43660bbb518","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Here is our current situation:\n\nOur funnel indicators show a 20.6% Sales Conversion Rate (SAL to Sale) and an average ticket of 4.5k MRR.\n\nIn Q2, we have already secured 14.1k new MRR.\n\nWe have 18 deals currently in negotiation in our Sales Pipeline and 12 SALs in the backlog, guaranteeing +27k in MRR (30 SALs * 20.6% Conversion Rate * 4.5K MRR average ticket).\n\nOur Q2 goal is to reach 80k new MRR, and we already have 41.1k (14.1k + 27k). Therefore, in the next few weeks, we need to close 9 new sales deals (around ~45 SALs)\n\nWithout the leads from Kia, Juca, Mau and Yuji at websummit, we have 10 Leads-1, 49 Leads-2 (they aren't SALs) , so despite of looks a lot of difficult, I believe we can make it.\n\nBut it will be difficult, so brace yourselves and let's fckng go!\n\nEsta é a nossa situação atual:\n\nNossos indicadores de funil mostram uma taxa de conversão de vendas de 20,6% (de SAL para venda) e um tíquete médio de 4,5k em MRR.\n\nNo segundo trimestre, já garantimos 14,1k em novos MRR.\n\nTemos 18 negociações em andamento no nosso pipeline de vendas e 12 SALs em backlog, garantindo +27k em MRR (30 SALs * 20,6% de taxa de conversão * tíquete médio de 4,5k em MRR).\n\nNosso objetivo para o segundo trimestre é alcançar 80k em novos MRR, e já temos 41,1k (14,1k + 27k). Portanto, nas próximas semanas, precisamos fechar 9 novas vendas (cerca de ~45 SALs) para atingir nossa meta\n\nSem os leads do Kia, Juca, Mau e Yuji do Web Summit, temos atualmente 10 leads em estágio 1 e 49 leads em estágio 2. Apesar de parecer difícil, eu ainda acredito que podemos progredir.","parentId":"2ce417ed-ee4b-46df-bc09-410e19482782","previousState":null},{"id":"2ce417ed-ee4b-46df-bc09-410e19482782","createdAt":"2023-04-14T14:47:08.870Z","value":2.9,"confidence":66,"keyResultId":"88c84700-4026-40e6-a539-a43660bbb518","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Mesma análise anterior: em linha com o MRR expected, mas aquém dos 10%. Nosso  crescimento começa a ficar mais agressivo em Abril","parentId":"1fe70830-1402-4276-8024-c221583821ae","previousState":null},{"id":"1fe70830-1402-4276-8024-c221583821ae","createdAt":"2023-03-03T14:58:18.855Z","value":3.2,"confidence":66,"keyResultId":"88c84700-4026-40e6-a539-a43660bbb518","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Tivemos uma alteração no P&L realizado do que foi coletado  em 02/02 (que indicava um aumento  de 6.1% em janeiro)\nQuando olhamos pro MRR projetado, estamos no eixo, nosso funil também está  saudável, mas os  resultados vão começar a surgir  mais  pro  final de março e abril","parentId":"c7a52437-ab8c-4d1b-984b-a805b062b008","previousState":null},{"id":"c7a52437-ab8c-4d1b-984b-a805b062b008","createdAt":"2023-02-13T15:20:04.834Z","value":6.1,"confidence":100,"keyResultId":"88c84700-4026-40e6-a539-a43660bbb518","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Apenas teremos alteração ao final do mês","parentId":"3e0ab133-b66a-4726-9359-c9956225fc44","previousState":null},{"id":"3e0ab133-b66a-4726-9359-c9956225fc44","createdAt":"2023-02-02T18:41:09.207Z","value":6.1,"confidence":100,"keyResultId":"88c84700-4026-40e6-a539-a43660bbb518","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Apesar de ser o primeiro mês e, teoricamente, deveria ser o mais fácil; a evolução que tivemos como time em questão de MQLs e Reuniões me deixa tranquilo que os próximos meses conseguiremos cobrir esse gap.\nPara fevereiro temos:\n- um master encaminhado para o grupo G7\n-  4 expands em negociação (NN, Bosch, Adeste e Ultragaz)","parentId":"9b7cfee6-fe1a-4790-9cff-d7fcd90048d7","previousState":null},{"id":"9b7cfee6-fe1a-4790-9cff-d7fcd90048d7","createdAt":"2023-01-20T16:49:59.270Z","value":0,"confidence":100,"keyResultId":"88c84700-4026-40e6-a539-a43660bbb518","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Fechamento mensal, apenas irei coletar dia 03/02","parentId":null,"previousState":null}],"objective":{"id":"6d77bd7f-a5d8-42b3-879d-51e11c8fc00d","createdAt":"2023-01-13T14:14:24.804Z","title":"Expand the company's reach","description":null,"updatedAt":"2023-01-13T14:14:28.525Z","cycleId":"4f01f61e-1616-40fa-8363-a930a2db2351","ownerId":"5aec0149-5535-42fb-b3d3-c20a5bda80c8","teamId":"f6790108-2b16-4077-bed0-103fc38175dd","mode":"PUBLISHED","cycle":{"id":"4f01f61e-1616-40fa-8363-a930a2db2351","createdAt":"2023-01-12T18:32:30.038Z","period":"2023","cadence":"YEARLY","active":true,"dateStart":"2023-01-01T00:00:00.000Z","dateEnd":"2023-12-31T00:00:00.000Z","updatedAt":"2023-01-12T18:32:30.038Z","teamId":"f6790108-2b16-4077-bed0-103fc38175dd","parentId":null}},"team":{"id":"f6790108-2b16-4077-bed0-103fc38175dd","createdAt":"2021-03-01T12:59:54.029Z","name":"Bud","updatedAt":"2021-10-12T16:39:15.305Z","ownerId":"16e46da6-39fc-4034-84c9-7b59a825d6e4","description":"Bud é a plataforma que te ajuda a implementar OKR de um jeito leve, envolvente e colaborativo.","gender":"MALE","parentId":null}},{"id":"0370802c-cf58-4324-bdea-ba7b4281be37","createdAt":"2023-01-13T14:16:29.019Z","title":"Create a reliable cashcow channel","initialValue":"0","goal":"100","format":"PERCENTAGE","type":"ASCENDING","updatedAt":"2023-01-16T11:20:12.381Z","ownerId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","objectiveId":"6d77bd7f-a5d8-42b3-879d-51e11c8fc00d","teamId":"f6790108-2b16-4077-bed0-103fc38175dd","description":"Um canal conhecido gerando 70% dos leads ou SALs","mode":"PUBLISHED","lastUpdatedBy":null,"commentCount":{"issue":0,"comment":0,"praisal":0,"question":0,"alignment":0,"suggestion":0,"improvement":0},"checkIns":[{"id":"4af1e026-d12f-4a71-b999-ae9e5f6fb166","createdAt":"2023-07-03T20:07:04.194Z","value":15,"confidence":100,"keyResultId":"0370802c-cf58-4324-bdea-ba7b4281be37","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"For higher avg ticket:\n1. Network\n2. Workshops\n\nFor lower avg ticket:\n1. Big tech conferences","parentId":"560795ff-c213-4145-9d16-f32d1f4457e6","previousState":{"goal":"100","mode":"PUBLISHED","type":"ASCENDING","title":"Create a reliable cashcow channel","format":"PERCENTAGE","ownerId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","description":"Um canal conhecido gerando 70% dos leads ou SALs"}},{"id":"560795ff-c213-4145-9d16-f32d1f4457e6","createdAt":"2023-06-18T21:26:41.240Z","value":15,"confidence":100,"keyResultId":"0370802c-cf58-4324-bdea-ba7b4281be37","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"I believe that after we land our learns, we'll advance a lot in this KR, but still we should expedite our testing process","parentId":"3084a3f4-6c18-428f-ad09-873883375a66","previousState":null},{"id":"3084a3f4-6c18-428f-ad09-873883375a66","createdAt":"2023-06-02T13:57:35.846Z","value":15,"confidence":100,"keyResultId":"0370802c-cf58-4324-bdea-ba7b4281be37","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"I haven't made no direct progress on this KR because this week I was focused on developing the Buyer's persona, which will be beneficial for the future endeavors","parentId":"e911448e-08ed-4c5f-966b-0b51632b43e5","previousState":null},{"id":"e911448e-08ed-4c5f-966b-0b51632b43e5","createdAt":"2023-05-26T13:55:38.894Z","value":15,"confidence":100,"keyResultId":"0370802c-cf58-4324-bdea-ba7b4281be37","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"We have 2 main channels in mid-market:\n- Network (personal and weme)\n- Workshops\n\nThere's a possibility of referral in mid-market and enterprise. I'll study how to create a referral program in B2B","parentId":"a9d00b68-537d-41df-9a15-3424e79fde16","previousState":null},{"id":"a9d00b68-537d-41df-9a15-3424e79fde16","createdAt":"2023-05-19T11:41:14.534Z","value":15,"confidence":100,"keyResultId":"0370802c-cf58-4324-bdea-ba7b4281be37","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"What we have learned so far is that those who come organically are primarily searching for a tool. It has been challenging to sell Pro and Master plans to them","parentId":"e96ac884-b7bc-47af-a46d-2ae10fc46a78","previousState":null},{"id":"e96ac884-b7bc-47af-a46d-2ae10fc46a78","createdAt":"2023-05-12T11:35:14.895Z","value":15,"confidence":100,"keyResultId":"0370802c-cf58-4324-bdea-ba7b4281be37","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Web Summit Rio se mostrou um excelente canal para geração de contatos. Ainda não convertemos em vendas (até porque não chegou nem perto do tempo de nosso ciclo).","parentId":"1eaa67b3-3fc5-401e-a382-75fb52dfcccf","previousState":null},{"id":"1eaa67b3-3fc5-401e-a382-75fb52dfcccf","createdAt":"2023-05-08T12:22:17.459Z","value":10,"confidence":100,"keyResultId":"0370802c-cf58-4324-bdea-ba7b4281be37","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"We had no meaningful updates","parentId":"240f7e0b-7a71-40e9-b169-7b6bc33dd5c1","previousState":null},{"id":"240f7e0b-7a71-40e9-b169-7b6bc33dd5c1","createdAt":"2023-04-14T14:44:48.168Z","value":10,"confidence":100,"keyResultId":"0370802c-cf58-4324-bdea-ba7b4281be37","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Nossos 3 principais canais:\n- Rede de Contatos\n- Eventos\n- Inbound\n\nPara termos um cashcow reliable, precisaremos focar em criar mecanismos de escala em Eventos e Inbound","parentId":"6e88b4f1-e63f-41c0-a737-aeae9866a223","previousState":null},{"id":"6e88b4f1-e63f-41c0-a737-aeae9866a223","createdAt":"2023-02-13T15:19:46.079Z","value":0,"confidence":100,"keyResultId":"0370802c-cf58-4324-bdea-ba7b4281be37","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Caio está avançando nos testes de canal, irei estudar sobre GTM essa semana","parentId":"7a6a8061-e8c6-4368-8a86-460b875e48e8","previousState":null},{"id":"7a6a8061-e8c6-4368-8a86-460b875e48e8","createdAt":"2023-02-02T18:42:46.296Z","value":0,"confidence":100,"keyResultId":"0370802c-cf58-4324-bdea-ba7b4281be37","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Hipóteses desenhadas para entendermos mais canais:\n\n[Canal/Cliente] Aceleradoras/Hubs - ACQ Aceleradoras de Inovação são a melhor porta de entrada para startups\n\n[Canal] Comunidades - ACQ atuar em Comunidades Whats (Agilistas/Especialistas) é um ótimo canal de geração de novas oportunidades;\n\nTemos outros testes mas que são mais voltados para  Clientes.","parentId":"ffd40627-7779-4a9d-ad38-13e3510b5add","previousState":null},{"id":"ffd40627-7779-4a9d-ad38-13e3510b5add","createdAt":"2023-01-20T19:52:59.991Z","value":0,"confidence":100,"keyResultId":"0370802c-cf58-4324-bdea-ba7b4281be37","userId":"a1c6f8ab-4b70-4b65-8341-445a3aaa4920","comment":"Acredito que podemos focar em Q1 para executar bem, criar baselines com a nova formação do time\nE começar a criar novas hipóteses mais para o final do quarter ou para Q2","parentId":null,"previousState":null}],"objective":{"id":"6d77bd7f-a5d8-42b3-879d-51e11c8fc00d","createdAt":"2023-01-13T14:14:24.804Z","title":"Expand the company's reach","description":null,"updatedAt":"2023-01-13T14:14:28.525Z","cycleId":"4f01f61e-1616-40fa-8363-a930a2db2351","ownerId":"5aec0149-5535-42fb-b3d3-c20a5bda80c8","teamId":"f6790108-2b16-4077-bed0-103fc38175dd","mode":"PUBLISHED","cycle":{"id":"4f01f61e-1616-40fa-8363-a930a2db2351","createdAt":"2023-01-12T18:32:30.038Z","period":"2023","cadence":"YEARLY","active":true,"dateStart":"2023-01-01T00:00:00.000Z","dateEnd":"2023-12-31T00:00:00.000Z","updatedAt":"2023-01-12T18:32:30.038Z","teamId":"f6790108-2b16-4077-bed0-103fc38175dd","paren