it.","mode":"PUBLISHED","lastUpdatedBy":null,"commentCount":{"issue":0,"comment":0,"praisal":0,"question":0,"alignment":0,"suggestion":0,"improvement":0},"checkIns":[{"id":"eb7d546c-67e4-4616-a0e9-4e0a460d1e5d","createdAt":"2023-06-26T19:45:54.804Z","value":0,"confidence":100,"keyResultId":"4d54c4bd-a52b-439c-bd70-1498c3530c41","userId":"94c1238b-182d-4861-a304-dac9f35e2391","comment":"The spotlight will be released in the next week. However, worth reflecting if the leader's assistant is the right approach. We are developing this theme in the next couple of weeks. ","parentId":"5bec7811-2c68-4aea-9a47-814473818a89","previousState":null},{"id":"5bec7811-2c68-4aea-9a47-814473818a89","createdAt":"2023-06-11T20:02:59.459Z","value":0,"confidence":100,"keyResultId":"4d54c4bd-a52b-439c-bd70-1498c3530c41","userId":"94c1238b-182d-4861-a304-dac9f35e2391","comment":"Spotlight will finish its development in the next couple of weeks :)","parentId":"da4e261c-04a2-409f-bfdc-bd746fe76b29","previousState":null},{"id":"da4e261c-04a2-409f-bfdc-bd746fe76b29","createdAt":"2023-05-15T13:30:07.158Z","value":0,"confidence":100,"keyResultId":"4d54c4bd-a52b-439c-bd70-1498c3530c41","userId":"94c1238b-182d-4861-a304-dac9f35e2391","comment":"I will review this KR in the current week.","parentId":"3ebf23bd-aa96-4cd0-8fda-5ec676c08079","previousState":null},{"id":"3ebf23bd-aa96-4cd0-8fda-5ec676c08079","createdAt":"2023-04-28T21:00:42.169Z","value":0,"confidence":100,"keyResultId":"4d54c4bd-a52b-439c-bd70-1498c3530c41","userId":"94c1238b-182d-4861-a304-dac9f35e2391","comment":"We do not have a functional assistant yet. I conclude that we need to improve our basic navigation and analytics first. Assistance is a manifold affordance; it can take different forms, not necessarily chat, not necessarily recommended actions. ","parentId":"2ee9ab9f-281f-419e-bd50-ce0c571f0176","previousState":null},{"id":"2ee9ab9f-281f-419e-bd50-ce0c571f0176","createdAt":"2023-03-19T17:06:50.448Z","value":0,"confidence":100,"keyResultId":"4d54c4bd-a52b-439c-bd70-1498c3530c41","userId":"94c1238b-182d-4861-a304-dac9f35e2391","comment":"This week Guto made great progress in our discovery process. I think we will focus on the clarification approach, where we will try to first clarify the objectives and key results for people to make sense of them before executing them. ","parentId":"d9e86aa4-cddc-440f-8b26-40711af3f9fb","previousState":null},{"id":"d9e86aa4-cddc-440f-8b26-40711af3f9fb","createdAt":"2023-02-23T17:09:24.932Z","value":0,"confidence":100,"keyResultId":"4d54c4bd-a52b-439c-bd70-1498c3530c41","userId":"94c1238b-182d-4861-a304-dac9f35e2391","comment":"We are currently in the discovery phase of the feature, which might become a habit tracker for the leader. We will understand if this is desirable in the next couple of weeks.","parentId":"cbed0bab-8de2-4f28-ad96-ecfb3a5b7ed9","previousState":null},{"id":"cbed0bab-8de2-4f28-ad96-ecfb3a5b7ed9","createdAt":"2023-02-07T22:12:30.351Z","value":0,"confidence":100,"keyResultId":"4d54c4bd-a52b-439c-bd70-1498c3530c41","userId":"94c1238b-182d-4861-a304-dac9f35e2391","comment":"We are currently in the discovery phase of the feature, which might become a habit tracker for the leader. We will understand if this is desirable in the next couple of weeks.","parentId":"2e99c1e4-2763-4577-83d8-708c91c42351","previousState":null},{"id":"2e99c1e4-2763-4577-83d8-708c91c42351","createdAt":"2023-01-30T18:20:03.715Z","value":0,"confidence":100,"keyResultId":"4d54c4bd-a52b-439c-bd70-1498c3530c41","userId":"94c1238b-182d-4861-a304-dac9f35e2391","comment":"Realizei uma primeira versão do roadmap do produto neste miro. \nhttps://miro.com/app/board/uXjVPuSQh4k=/","parentId":null,"previousState":null}],"objective":{"id":"9f4682c2-b52b-48aa-a658-fbe2a49b2caf","createdAt":"2023-01-13T14:10:40.992Z","title":"Secure funding to support future growth","description":null,"updatedAt":"2023-01-13T14:10:44.613Z","cycleId":"4f01f61e-1616-40fa-8363-a930a2db2351","ownerId":